document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".reveal-up");if("IntersectionObserver"in window){const t=new IntersectionObserver(e=>{e.forEach(e=>{if(e.isIntersecting){const r=e.target.getAttribute("data-delay");r&&e.target.style.setProperty("--reveal-delay",`${r}ms`),e.target.classList.add("in-view"),t.unobserve(e.target)}})},{threshold:.15,rootMargin:"0px 0px -40px 0px"});e.forEach(e=>t.observe(e))}else e.forEach(e=>e.classList.add("in-view"))});